import React, { useState, useEffect, useRef, useCallback } from 'react';
import api from '../lib/api';

const Terminal = () => {
  const [tabs, setTabs] = useState([]);
  const [activeTab, setActiveTab] = useState(null);
  const [devices, setDevices] = useState([]);
  const [showDeviceList, setShowDeviceList] = useState(false);
  const [commandHistory, setCommandHistory] = useState([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  const terminalRef = useRef(null);
  const inputRef = useRef(null);
  const wsRef = useRef(null);

  // Carregar dispositivos
  useEffect(() => {
    loadDevices();
  }, []);

  const loadDevices = async () => {
    try {
      const response = await api.get('/devices/');
      setDevices(response.data.results || response.data || []);
    } catch (error) {
      console.error('Error loading devices:', error);
    }
  };

  // Criar nova aba de terminal
  const openNewTab = (device) => {
    const newTab = {
      id: Date.now(),
      device: device,
      name: device.name || device.hostname || device.ip || 'Terminal',
      ip: device.ip || device.ip_address,
      port: device.ssh_port || 22,
      username: device.username || device.ssh_user || 'root',
      status: 'connecting',
      output: [
        `\x1b[1;36m╔══════════════════════════════════════════════════════════════╗`,
        `\x1b[1;36m║\x1b[0m  LOR CGR Terminal - Conectando a \x1b[1;33m${device.name || device.ip}\x1b[0m`,
        `\x1b[1;36m║\x1b[0m  Host: \x1b[1;37m${device.ip || device.ip_address}\x1b[0m  Porta: \x1b[1;37m${device.ssh_port || 22}\x1b[0m`,
        `\x1b[1;36m╚══════════════════════════════════════════════════════════════╝`,
        ''
      ],
      input: '',
      history: []
    };

    setTabs(prev => [...prev, newTab]);
    setActiveTab(newTab.id);
    setShowDeviceList(false);

    // Conectar via WebSocket
    connectTerminal(newTab);
  };

  // Conectar terminal via WebSocket
  const connectTerminal = (tab) => {
    try {
      const wsProtocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      const wsUrl = `${wsProtocol}//${window.location.host}/ws/terminal/${tab.id}/`;

      const ws = new WebSocket(wsUrl);

      ws.onopen = () => {
        updateTab(tab.id, { 
          status: 'connected',
          output: [...tab.output, '\x1b[1;32m✓ Conectado!\x1b[0m', '']
        });

        // Enviar credenciais de conexão
        ws.send(JSON.stringify({
          type: 'connect',
          host: tab.ip,
          port: tab.port,
          username: tab.username
        }));
      };

      ws.onmessage = (event) => {
        const data = JSON.parse(event.data);
        if (data.type === 'output') {
          appendOutput(tab.id, data.data);
        } else if (data.type === 'status') {
          updateTab(tab.id, { status: data.status });
        }
      };

      ws.onerror = () => {
        appendOutput(tab.id, '\x1b[1;31m✗ Erro de conexão\x1b[0m');
        updateTab(tab.id, { status: 'error' });
      };

      ws.onclose = () => {
        appendOutput(tab.id, '\x1b[1;33m⚠ Conexão fechada\x1b[0m');
        updateTab(tab.id, { status: 'disconnected' });
      };

      wsRef.current = { ...wsRef.current, [tab.id]: ws };

    } catch (error) {
      // Modo simulação se WebSocket não disponível
      startSimulation(tab);
    }
  };

  // Modo simulação
  const startSimulation = (tab) => {
    updateTab(tab.id, { 
      status: 'simulation',
      output: [
        ...tab.output,
        '\x1b[1;33m⚠ Modo Simulação (WebSocket não disponível)\x1b[0m',
        '\x1b[90mConectando ao servidor...\x1b[0m',
        '',
        `\x1b[1;32m${tab.username}@${tab.ip}\x1b[0m:\x1b[1;34m~\x1b[0m$ `
      ]
    });
  };

  // Atualizar aba
  const updateTab = useCallback((tabId, updates) => {
    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, ...updates } : t));
  }, []);

  // Adicionar output
  const appendOutput = useCallback((tabId, text) => {
    setTabs(prev => prev.map(t => 
      t.id === tabId 
        ? { ...t, output: [...t.output, text] }
        : t
    ));
    scrollToBottom(tabId);
  }, []);

  // Scroll para baixo
  const scrollToBottom = (tabId) => {
    setTimeout(() => {
      const terminal = document.getElementById(`terminal-${tabId}`);
      if (terminal) {
        terminal.scrollTop = terminal.scrollHeight;
      }
    }, 10);
  };

  // Enviar comando
  const sendCommand = (tabId, command) => {
    const tab = tabs.find(t => t.id === tabId);
    if (!tab) return;

    // Adicionar ao histórico
    if (command.trim()) {
      setCommandHistory(prev => [...prev, command]);
      setHistoryIndex(-1);
    }

    // Mostrar comando no terminal
    appendOutput(tabId, `\x1b[1;32m${tab.username}@${tab.ip}\x1b[0m:\x1b[1;34m~\x1b[0m$ ${command}`);

    // Enviar via WebSocket ou simular
    const ws = wsRef.current?.[tabId];
    if (ws && ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({ type: 'input', data: command + '\n' }));
    } else {
      // Simulação
      simulateCommand(tabId, command, tab);
    }
  };

  // Simular comando
  const simulateCommand = (tabId, command, tab) => {
    const cmd = command.trim().toLowerCase();
    const args = command.trim().split(' ').slice(1);

    setTimeout(() => {
      let output = '';

      switch (cmd.split(' ')[0]) {
        case 'ls':
          output = args.includes('-la') || args.includes('-l')
            ? 'total 48\ndrwxr-xr-x  5 root root 4096 Feb 15 10:00 .\ndrwxr-xr-x 20 root root 4096 Feb 10 09:00 ..\n-rw-r--r--  1 root root  220 Feb 10 09:00 .bash_logout\n-rw-r--r--  1 root root 3771 Feb 10 09:00 .bashrc\ndrwxr-xr-x  2 root root 4096 Feb 12 14:00 .cache\ndrwxr-xr-x  3 root root 4096 Feb 11 11:00 .local\n-rw-r--r--  1 root root  807 Feb 10 09:00 .profile\ndrwxr-xr-x  2 root root 4096 Feb 13 16:00 scripts'
            : 'cache  local  scripts  snap';
          break;
        case 'pwd':
          output = '/root';
          break;
        case 'whoami':
          output = tab.username;
          break;
        case 'hostname':
          output = tab.name.toLowerCase().replace(/\s+/g, '-');
          break;
        case 'date':
          output = new Date().toString();
          break;
        case 'uptime':
          output = ' 10:30:00 up 5 days, 12:34,  1 user,  load average: 0.15, 0.10, 0.05';
          break;
        case 'free':
          output = '              total        used        free      shared  buff/cache   available\nMem:        8192000     1234567     5432109       12345     1525324     6654321\nSwap:       2048000           0     2048000';
          break;
        case 'df':
          output = 'Filesystem     1K-blocks    Used Available Use% Mounted on\n/dev/sda1       51475068 8234512  40610472  17% /\ntmpfs            4096000       0   4096000   0% /dev/shm';
          break;
        case 'ip':
        case 'ifconfig':
          output = 'eth0: flags=4163<UP,BROADCAST,RUNNING,MULTICAST>  mtu 1500\n        inet ' + tab.ip + '  netmask 255.255.255.0  broadcast ' + tab.ip.substring(0, tab.ip.lastIndexOf('.')) + '.255\n        ether 00:11:22:33:44:55  txqueuelen 1000  (Ethernet)\n        RX packets 1234567  bytes 987654321 (987.6 MB)\n        TX packets 234567  bytes 12345678 (12.3 MB)';
          break;
        case 'ping':
          if (args[0]) {
            output = `PING ${args[0]} (93.184.216.34): 56 data bytes\n64 bytes from 93.184.216.34: seq=0 ttl=56 time=12.345 ms\n64 bytes from 93.184.216.34: seq=1 ttl=56 time=11.234 ms\n64 bytes from 93.184.216.34: seq=2 ttl=56 time=13.456 ms\n\n--- ${args[0]} ping statistics ---\n3 packets transmitted, 3 packets received, 0% packet loss`;
          } else {
            output = 'ping: usage error: Destination address required';
          }
          break;
        case 'clear':
          updateTab(tabId, { output: [] });
          return;
        case 'exit':
        case 'quit':
          closeTab(tabId);
          return;
        case 'help':
          output = 'Comandos disponíveis:\n  ls [-la]    - Lista arquivos\n  pwd         - Diretório atual\n  whoami      - Usuário atual\n  hostname    - Nome do host\n  date        - Data e hora\n  uptime      - Tempo de atividade\n  free        - Uso de memória\n  df          - Uso de disco\n  ip/ifconfig - Interfaces de rede\n  ping <host> - Testa conectividade\n  clear       - Limpa tela\n  exit        - Fecha terminal';
          break;
        case '':
          break;
        default:
          output = `bash: ${cmd.split(' ')[0]}: command not found`;
      }

      if (output) {
        appendOutput(tabId, output);
      }
      appendOutput(tabId, '');
      appendOutput(tabId, `\x1b[1;32m${tab.username}@${tab.ip}\x1b[0m:\x1b[1;34m~\x1b[0m$ `);

    }, 100);
  };

  // Fechar aba
  const closeTab = (tabId, e) => {
    if (e) e.stopPropagation();

    // Fechar WebSocket
    const ws = wsRef.current?.[tabId];
    if (ws) {
      ws.close();
      delete wsRef.current[tabId];
    }

    setTabs(prev => {
      const newTabs = prev.filter(t => t.id !== tabId);
      if (activeTab === tabId && newTabs.length > 0) {
        setActiveTab(newTabs[newTabs.length - 1].id);
      } else if (newTabs.length === 0) {
        setActiveTab(null);
      }
      return newTabs;
    });
  };

  // Handler de teclado
  const handleKeyDown = (e, tabId) => {
    const tab = tabs.find(t => t.id === tabId);
    if (!tab) return;

    if (e.key === 'Enter') {
      const input = e.target.value;
      sendCommand(tabId, input);
      e.target.value = '';
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (commandHistory.length > 0) {
        const newIndex = historyIndex < commandHistory.length - 1 ? historyIndex + 1 : historyIndex;
        setHistoryIndex(newIndex);
        e.target.value = commandHistory[commandHistory.length - 1 - newIndex] || '';
      }
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (historyIndex > 0) {
        const newIndex = historyIndex - 1;
        setHistoryIndex(newIndex);
        e.target.value = commandHistory[commandHistory.length - 1 - newIndex] || '';
      } else {
        setHistoryIndex(-1);
        e.target.value = '';
      }
    } else if (e.key === 'Tab') {
      e.preventDefault();
      // Autocomplete básico
      const input = e.target.value;
      const commands = ['ls', 'pwd', 'whoami', 'hostname', 'date', 'uptime', 'free', 'df', 'ip', 'ifconfig', 'ping', 'clear', 'exit', 'help'];
      const matches = commands.filter(c => c.startsWith(input));
      if (matches.length === 1) {
        e.target.value = matches[0] + ' ';
      } else if (matches.length > 1) {
        appendOutput(tabId, matches.join('  '));
        appendOutput(tabId, `\x1b[1;32m${tab.username}@${tab.ip}\x1b[0m:\x1b[1;34m~\x1b[0m$ ${input}`);
      }
    } else if (e.ctrlKey && e.key === 'c') {
      appendOutput(tabId, '^C');
      appendOutput(tabId, `\x1b[1;32m${tab.username}@${tab.ip}\x1b[0m:\x1b[1;34m~\x1b[0m$ `);
      e.target.value = '';
    } else if (e.ctrlKey && e.key === 'l') {
      e.preventDefault();
      updateTab(tabId, { output: [] });
    }
  };

  // Focar no input quando clicar no terminal
  const focusInput = () => {
    if (inputRef.current) {
      inputRef.current.focus();
    }
  };

  // Renderizar output com cores ANSI
  const renderOutput = (text) => {
    // Simplified ANSI rendering
    let formatted = text
      .replace(/\x1b\[1;36m/g, '<span class="text-cyan-400 font-bold">')
      .replace(/\x1b\[1;32m/g, '<span class="text-green-400 font-bold">')
      .replace(/\x1b\[1;33m/g, '<span class="text-yellow-400 font-bold">')
      .replace(/\x1b\[1;31m/g, '<span class="text-red-400 font-bold">')
      .replace(/\x1b\[1;34m/g, '<span class="text-blue-400 font-bold">')
      .replace(/\x1b\[1;37m/g, '<span class="text-white font-bold">')
      .replace(/\x1b\[90m/g, '<span class="text-gray-500">')
      .replace(/\x1b\[0m/g, '</span>');

    return <span dangerouslySetInnerHTML={{ __html: formatted }} />;
  };

  const currentTab = tabs.find(t => t.id === activeTab);

  return (
    <div className="flex flex-col h-[calc(100vh-150px)] bg-gray-900 rounded-lg overflow-hidden border border-gray-700">
      {/* Tabs Header */}
      <div className="flex items-center bg-gray-800 border-b border-gray-700">
        <div className="flex-1 flex overflow-x-auto">
          {tabs.map(tab => (
            <div
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center space-x-2 px-4 py-3 cursor-pointer border-r border-gray-700 min-w-max ${
                activeTab === tab.id 
                  ? 'bg-gray-900 text-white border-t-2 border-t-blue-500' 
                  : 'text-gray-400 hover:bg-gray-700 hover:text-white'
              }`}
            >
              <span className={`w-2 h-2 rounded-full ${
                tab.status === 'connected' ? 'bg-green-500' :
                tab.status === 'connecting' ? 'bg-yellow-500 animate-pulse' :
                tab.status === 'error' ? 'bg-red-500' :
                tab.status === 'simulation' ? 'bg-orange-500' : 'bg-gray-500'
              }`}></span>
              <span className="text-sm font-medium">{tab.name}</span>
              <button
                onClick={(e) => closeTab(tab.id, e)}
                className="text-gray-500 hover:text-red-400 ml-2"
              >
                ✕
              </button>
            </div>
          ))}
        </div>

        <button
          onClick={() => setShowDeviceList(!showDeviceList)}
          className="px-4 py-3 text-gray-400 hover:text-white hover:bg-gray-700 border-l border-gray-700"
          title="Nova conexão"
        >
          ➕
        </button>
      </div>

      {/* Device List Dropdown */}
      {showDeviceList && (
        <div className="absolute top-32 right-8 w-80 bg-gray-800 border border-gray-700 rounded-lg shadow-xl z-50 max-h-96 overflow-y-auto">
          <div className="p-3 border-b border-gray-700 flex items-center justify-between">
            <span className="text-white font-medium">Selecionar Dispositivo</span>
            <button onClick={() => setShowDeviceList(false)} className="text-gray-400 hover:text-white">✕</button>
          </div>
          <div className="p-2">
            {devices.length === 0 ? (
              <p className="text-gray-400 text-center py-4">Nenhum dispositivo disponível</p>
            ) : (
              devices.map(device => (
                <button
                  key={device.id}
                  onClick={() => openNewTab(device)}
                  className="w-full flex items-center space-x-3 p-3 rounded-lg hover:bg-gray-700 text-left transition"
                >
                  <div className={`w-2 h-2 rounded-full ${device.is_active !== false ? 'bg-green-500' : 'bg-red-500'}`}></div>
                  <div className="flex-1">
                    <p className="text-white font-medium">{device.name || device.hostname || 'Sem nome'}</p>
                    <p className="text-gray-400 text-sm">{device.ip || device.ip_address}</p>
                  </div>
                  <span className="text-gray-500 text-xs">{device.device_type || 'N/A'}</span>
                </button>
              ))
            )}
          </div>
        </div>
      )}

      {/* Terminal Content */}
      {currentTab ? (
        <div 
          className="flex-1 bg-gray-900 p-4 font-mono text-sm overflow-y-auto cursor-text"
          id={`terminal-${currentTab.id}`}
          onClick={focusInput}
        >
          {currentTab.output.map((line, index) => (
            <div key={index} className="whitespace-pre-wrap">
              {renderOutput(line)}
            </div>
          ))}

          {/* Input */}
          <div className="flex items-center mt-1">
            <input
              ref={inputRef}
              type="text"
              className="flex-1 bg-transparent text-green-400 outline-none font-mono"
              onKeyDown={(e) => handleKeyDown(e, currentTab.id)}
              autoFocus
              placeholder={currentTab.status === 'connected' ? '' : 'Digite um comando...'}
              disabled={currentTab.status === 'connecting'}
            />
          </div>
        </div>
      ) : (
        <div className="flex-1 flex flex-col items-center justify-center text-gray-400">
          <div className="text-6xl mb-4">💻</div>
          <h3 className="text-xl font-medium text-white mb-2">Terminal SSH</h3>
          <p className="text-gray-400 mb-4">Clique em + para abrir uma nova conexão</p>
          <button
            onClick={() => setShowDeviceList(true)}
            className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition"
          >
            Nova Conexão
          </button>
        </div>
      )}

      {/* Status Bar */}
      {currentTab && (
        <div className="flex items-center justify-between px-4 py-2 bg-gray-800 border-t border-gray-700 text-xs">
          <div className="flex items-center space-x-4">
            <span className="text-gray-400">
              Host: <span className="text-white">{currentTab.ip}</span>
            </span>
            <span className="text-gray-400">
              Porta: <span className="text-white">{currentTab.port}</span>
            </span>
            <span className="text-gray-400">
              Usuário: <span className="text-white">{currentTab.username}</span>
            </span>
          </div>
          <div className="flex items-center space-x-2">
            <span className={`px-2 py-1 rounded text-xs ${
              currentTab.status === 'connected' ? 'bg-green-600/20 text-green-400' :
              currentTab.status === 'simulation' ? 'bg-orange-600/20 text-orange-400' :
              currentTab.status === 'connecting' ? 'bg-yellow-600/20 text-yellow-400' :
              'bg-red-600/20 text-red-400'
            }`}>
              {currentTab.status === 'connected' ? '🟢 Conectado' :
               currentTab.status === 'simulation' ? '🟠 Simulação' :
               currentTab.status === 'connecting' ? '🟡 Conectando...' :
               '🔴 Desconectado'}
            </span>
          </div>
        </div>
      )}
    </div>
  );
};

export default Terminal;
